content:
{
  "sentences": [
    {
      "text": "我想約朋友一起去喝咖啡。",
      "pinyin": "Wǒ xiǎng yuē péngyǒu yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "wo3 xiang3 yue1 peng2you3 yi1qi3 qu4 he1 ka1fei1.",
      "translation_en": "I want to make plans with a friend to go drink coffee together.",
      "translation_ko": "친구와 함께 커피를 마시러 가기로 약속하고 싶어요."
    },
    {
      "text": "你想約誰一起去吃飯？",
      "pinyin": "Nǐ xiǎng yuē shéi yīqǐ qù chīfàn?",
      "pinyin_numeric": "ni3 xiang3 yue1 shei2 yi1qi3 qu4 chi1fan4?",
      "translation_en": "Who do you want to make plans with to go eat together?",
      "translation_ko": "누구와 함께 밥을 먹으러 가기로 약속하고 싶어요?"
    },
    {
      "text": "他不想看電影，他想去逛街。",
      "pinyin": "Tā bù xiǎng kàn diànyǐng, tā xiǎng qù guàngjiē.",
      "pinyin_numeric": "ta1 bu4 xiang3 kan4 dian4ying3, ta1 xiang3 qu4 guang4jie1.",
      "pinyin_numeric": "ta1 bu4 xiang3 kan4 dian4ying3, ta1 xiang3 qu4 guang4jie1.",
      "translation_en": "He doesn't want to watch a movie; he wants to go shopping.",
      "translation_ko": "그는 영화를 보고 싶지 않고, 쇼핑하러 가고 싶어요."
    },
    {
      "text": "我們想約時間一起聊天。",
      "pinyin": "Wǒmen xiǎng yuē shíjiān yīqǐ liáotiān.",
      "pinyin_numeric": "wo3men xiang3 yue1 shi2jian1 yi1qi3 liao2tian1.",
      "translation_en": "We want to arrange a time to chat together.",
      "translation_ko": "우리는 함께 이야기할 시간을 약속하고 싶어요."
    },
    {
      "text": "你想約在哪裡見面？",
      "pinyin": "Nǐ xiǎng yuē zài nǎlǐ jiànmiàn?",
      "pinyin_numeric": "ni3 xiang3 yue1 zai4 na3li3 jian4mian4?",
      "translation_en": "Where do you want to arrange to meet?",
      "translation_ko": "어디에서 만나기로 약속하고 싶어요?"
    },
    {
      "text": "她不想改時間，她想準時到。",
      "pinyin": "Tā bù xiǎng gǎi shíjiān, tā xiǎng zhǔnshí dào.",
      "pinyin_numeric": "ta1 bu4 xiang3 gai3 shi2jian1, ta1 xiang3 zhun3shi2 dao4.",
      "translation_en": "She doesn't want to change the time; she wants to arrive on time.",
      "translation_ko": "그녀는 시간을 바꾸고 싶지 않고, 정시에 도착하고 싶어요."
    },
    {
      "text": "我想約他一起去吃飯，可是他沒空。",
      "pinyin": "Wǒ xiǎng yuē tā yīqǐ qù chīfàn, kěshì tā méi kòng.",
      "pinyin_numeric": "wo3 xiang3 yue1 ta1 yi1qi3 qu4 chi1fan4, ke3shi4 ta1 mei2 kong4.",
      "translation_en": "I want to make plans with him to go eat together, but he's not free.",
      "translation_ko": "그와 함께 밥을 먹으러 가기로 약속하고 싶은데, 그가 시간이 없어요."
    },
    {
      "text": "你們想約在咖啡店還是電影院？",
      "pinyin": "Nǐmen xiǎng yuē zài kāfēidiàn háishì diànyǐngyuàn?",
      "pinyin_numeric": "ni3men xiang3 yue1 zai4 ka1fei1dian4 hai2shi4 dian4ying3yuan4?",
      "translation_en": "Do you want to arrange to meet at a coffee shop or a movie theater?",
      "translation_ko": "커피숍에서 만나기로 할까요, 아니면 영화관에서 만나기로 할까요?"
    },
    {
      "text": "他不想取消約會，他想提早見面。",
      "pinyin": "Tā bù xiǎng qǔxiāo yuēhuì, tā xiǎng tízǎo jiànmiàn.",
      "pinyin_numeric": "ta1 bu4 xiang3 qu3xiao1 yue1hui4, ta1 xiang3 ti2zao3 jian4mian4.",
      "translation_en": "He doesn't want to cancel the appointment; he wants to meet earlier.",
      "translation_ko": "그는 약속을 취소하고 싶지 않고, 더 일찍 만나고 싶어요."
    },
    {
      "text": "我想約她一起去逛街，她說可以啊。",
      "pinyin": "Wǒ xiǎng yuē tā yīqǐ qù guàngjiē, tā shuō kěyǐ a.",
      "pinyin_numeric": "wo3 xiang3 yue1 ta1 yi1qi3 qu4 guang4jie1, ta1 shuo1 ke3yi3 a.",
      "translation_en": "I want to make plans with her to go shopping together, and she said okay.",
      "translation_ko": "그녀와 함께 쇼핑하러 가기로 약속하고 싶은데, 그녀가 좋다고 했어요."
    }
  ]
}
